using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
if (!File.Exists(dataPath))
    dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "customers.csv");

// Load CSV with Churned as string, then map to bool Label
var rawData = mlContext.Data.LoadFromTextFile<CustomerRawData>(dataPath, hasHeader: true, separatorChar: ',');

// Convert "Yes"/"No" to bool Label
var mappingPipeline = mlContext.Transforms.CustomMapping<CustomerRawData, ChurnLabelMapping>(
    (input, output) => { output.Label = input.Churned == "Yes"; },
    contractName: "ChurnMapping");

var mappedData = mappingPipeline.Fit(rawData).Transform(rawData);

// Build the training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

// Train/test split
var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2, seed: 42);

// Train the model
var model = pipeline.Fit(split.TrainSet);

// Evaluate
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"F1: {metrics.F1Score:F4}");

// Save model to memory stream for PredictionEnginePool
using var modelStream = new MemoryStream();
mlContext.Model.Save(model, mappedData.Schema, modelStream);
modelStream.Position = 0;
var modelBytes = modelStream.ToArray();

// Register PredictionEnginePool
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromSerializedModel(new MemoryStream(modelBytes));

var app = builder.Build();

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (CustomerData customer, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

// Input class matching CSV for raw loading (with Churned as string)
public class CustomerRawData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = string.Empty;
}

// Custom mapping output
public class ChurnLabelMapping
{
    public bool Label { get; set; }
}

// Input class for prediction (no Churned column needed)
public class CustomerData
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = string.Empty;
    public float PurchaseHistory { get; set; }

    [ColumnName("Label")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

